var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......진동이 멎었군.","JPN":"……振動が止まった。","ENG":"The vibrations stopped.","TWN":"……震動停止了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"느껴지는 에너지 파형으로 보면, 아마 급하게 다이브 시퀀스를 진행한 것 같은데......","JPN":"エネルギー波形からして、急ぎでダイブシーケンスを進めたようだが……","ENG":"Judging by the energy waves, they must’ve executed an emergency dive sequence...","TWN":"從感受到的能量波形來看，應該是進行了緊急躍入……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"어디로 떨어질지는 모르겠지만, 살아 돌아가려면 항해사가 운이 좋길 바라야겠군.","JPN":"どこに落下するかは測定不能。航海士の運次第で生死が決まる。","ENG":"Wherever we end up dropping, hopefully luck is on the navigator’s side... if we are to return alive.","TWN":"雖然不知道會降落到哪裡，但想要活下來的話，就得看駕駛員的運氣了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"밖의 네 동료들은 어때?","JPN":"外にいるあなたの同僚たちはどうなのですか？","ENG":"How about your colleagues out there?","TWN":"妳那些在外面的同事怎麼樣了？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"걱정되지 않나?","JPN":"気にならないのですか？","ENG":"Aren't you worried about them?","TWN":"妳不擔心嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":".....이것도 생각했던 것과는 다르군.","JPN":"……これも想定されていない事態。","ENG":"This too is different from what I expected.","TWN":"……這也和我想得不一樣啊。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"내게 물어 볼 말이 많을 줄 알았는데.","JPN":"私に聞きたいことが多いのではと思っていたが。","ENG":"I thought you’d have many questions for me.","TWN":"我還以為妳會有很多話問我。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......내가? 어째서?","JPN":"……私が？　どうして？","ENG":"Me? Why?","TWN":"……我？為什麼？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"모체의 최후에 대한 격렬한 감정반응이나, 나를 처음 봤을 때 나타낸 동요 등을 고려했을 때......","JPN":"母体の最期に対する激しい感情反応や、私を初めて見た時の動揺などから……","ENG":"Given the violent emotional response to the death of my source, and your reaction upon seeing me for the first time...","TWN":"從我母體死亡的激烈感情反應，還有妳第一次見到我的時候十分動搖……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"내 모체에 대해 궁금한 점이 많을 거라고 생각했다.","JPN":"私の母体について、知りたいことが多いのではと想定していた。","ENG":"I thought you’d have many questions about my source.","TWN":"我覺得妳會對我的母體有很多問題。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇다고 해도, 왜 네게 그런 걸 물어야 하지?","JPN":"だとしても、あんたにそんなことを聞いてどうする？","ENG":"Even if I did, why would I ask you about it?","TWN":"就算如此，為什麼要問妳呢？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네 입으로 말했잖아. 넌 나래와 다른 존재라고.","JPN":"あんたの口から言ったじゃない。自分はナルミとは異なる存在だって。","ENG":"You said so yourself. You're not Narae.","TWN":"妳自己不是也說了嘛，妳不是娜拉。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"물론 그렇다. 하지만 관련이 전혀 없는 것은 아니지.","JPN":"もちろんそうだ。しかし、全く関係がないわけではない。","ENG":"Indeed. But I wouldn’t say I’m completely unrelated.","TWN":"當然。但也不是完全沒有關連。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"기억과 정체성이라는 것은 분명 다르지만, 완전히 분리할 수 있는 것도 아니다.","JPN":"記憶とアイデンティティは明らかに異なるものだが、完全に切り離すこともできない。","ENG":"My memories and identity may be distinct from hers, but they are not completely inseparable either.","TWN":"記憶和本質雖然不同，但也無法完全分開。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"나 또한 그 영향 아래에 있는 것을 부정할 필요는 없겠지.","JPN":"私も影響されていることを否定しない。","ENG":"I cannot deny the fact that I too am under the residual influence of my source.","TWN":"而且不需要否定我受到了母體的影響。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"원한다면 모체가 어떤 생각을 했었는지 말해 줄 수 있다.","JPN":"望むなら、母体の考えを伝えることもできる。","ENG":"If you wish, I could tell you about what the source was thinking.","TWN":"妳想知道的話，我可以告訴妳母體的想法。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"너에 대한 감정, 가족에 대한 감정......","JPN":"あなたへの気持ち、家族への想い……","ENG":"Her feelings about you... about family...","TWN":"對妳的感情，對家人的感情……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"원한다면 최후의 순간에 떠올린 생각까지.","JPN":"望むなら、最期の瞬間に思い浮かべたことまでも。","ENG":"Even her final thoughts right before she died, should you wish to hear them.","TWN":"妳想知道的話，她最後一刻的想法也可以告訴妳。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};